const fs   = require('fs');
const path = require('path');

const params  = $('Set Global Parameters').first().json;
const deckRaw = $input.first().json;
const deck    = deckRaw.data || deckRaw;

const deckDir = deck.Assets.Directory.replace(/\\/g, '/');
const geom    = deck.Geometries;

const jobs = [];
let skipped = 0;

for (const cardRef of deck.Cards || []) {
  const cardJsonPath = path.resolve(deckDir, cardRef.File).replace(/\\/g, '/');
  if (!cardJsonPath.startsWith(path.resolve(deckDir).replace(/\\/g, '/'))) throw new Error('Path traversal detected: ' + cardRef.File);
  if (!fs.existsSync(cardJsonPath)) {
    console.warn('[Build Card Face Job List] Missing card JSON: ' + cardJsonPath);
    continue;
  }

  const cardData = JSON.parse(fs.readFileSync(cardJsonPath, 'utf8'));
  const meta     = cardData['data.Cards'];
  if (!meta) continue;

  const cardName    = meta.Card;
  const cardDir     = ((meta.Directory) || path.join(deckDir, 'Cards')).replace(/\\/g, '/');
  const uprightImage = meta.Assets && meta.Assets.UprightImage;

  if (!uprightImage) {
    console.warn('[Build Card Face Job List] No UprightImage for: ' + cardName);
    continue;
  }

  const outputPath = cardDir + '/' + uprightImage;

  if (fs.existsSync(outputPath)) {
    console.warn('[Build Card Face Job List] Skipping existing: ' + uprightImage);
    skipped++;
    continue;
  }

  const panels = ['upright', 'between', 'reversed'].map(function(ori) {
    const rec = (meta.records || []).find(function(r) { return r.Orientation === ori; });
    return {
      label:       ori.charAt(0).toUpperCase() + ori.slice(1),
      description: (rec && rec.Description) || '',
      advice:      (rec && rec.Advice)      || ''
    };
  });

  jobs.push({
    CardName:    cardName,
    OutputPath:  outputPath,
    Panels:      panels,
    CardWidth:   (geom.Size   && geom.Size.Width)   || 680,
    CardHeight:  (geom.Size   && geom.Size.Height)  || 1100,
    TitleHeight: (geom.Title  && geom.Title.Height) || 18,
    BodyWidth:   (geom.Body   && geom.Body.Width)   || 660,
    PanelHeight: (geom.Images && geom.Images.Height)|| 300,
    TitleFont:   (geom.Title  && geom.Title.Font)   || 'pala.ttf',
    BodyFont:    (geom.Body   && geom.Body.Font)    || 'constan.ttf',
    ImageWidth:  (geom.Images && geom.Images.Width) || 300,
    TextWidth:   (geom.Text   && geom.Text.Width)   || 320,
    CardDir:     cardDir,
    CardNameFS:  cardName.replace(/ /g, '_'),
    PythonExe:   params.PythonExe,
    TempDir:     params.TempDir
  });
}

if (jobs.length === 0 && skipped === 0) {
  throw new Error(
    '[Build Card Face Job List] No jobs created. ' +
    'Check that deck.Cards is populated and card JSON files exist in ' + deckDir
  );
}

if (jobs.length === 0) {
  throw new Error(
    '[Build Card Face Job List] All ' + skipped + ' card faces already exist. ' +
    'Delete CARD_*.png files from the Cards directory to regenerate.'
  );
}

console.log('[Build Card Face Job List] Created ' + jobs.length + ' jobs (' + skipped + ' already exist, skipped).');
return jobs.map(function(j) { return { json: j }; });

const fs             = require('fs');
const path           = require('path');
const { execFileSync } = require('child_process');

const allJobs = $input.all().map(function(i) { return i.json; });
const results = [];
const errors  = [];

if (allJobs.length === 0) {
  throw new Error('[Generate Card Faces] No jobs received.');
}

const tempDir = allJobs[0].TempDir;
fs.mkdirSync(tempDir, { recursive: true });

// Python PIL rendering script (written once, reused for every card)
const pyScript = `import sys, json, os
from PIL import Image, ImageDraw, ImageFont

FONT_DIR = 'C:/Windows/Fonts'

def resolve_font(name, size):
    fp = FONT_DIR + '/' + name
    if os.path.exists(fp):
        return ImageFont.truetype(fp, size)
    import sys as _sys
    print('Warning: font not found ' + fp, file=_sys.stderr)
    return ImageFont.load_default()

def wrap_text(draw, text, font, max_w):
    words = text.split()
    lines = []
    cur = ''
    for w in words:
        t = (cur + ' ' + w).strip()
        try:
            px = draw.textlength(t, font=font)
        except Exception:
            px = len(t) * 7
        if px <= max_w:
            cur = t
        else:
            if cur:
                lines.append(cur)
            cur = w
    if cur:
        lines.append(cur)
    return lines

def draw_block(draw, text, font, x, y, max_w, bot, color, lh):
    for line in wrap_text(draw, text, font, max_w):
        if y + lh > bot:
            draw.text((x, y), '...', font=font, fill=color)
            break
        draw.text((x, y), line, font=font, fill=color)
        y += lh
    return y

d            = json.load(open(sys.argv[1], encoding='utf-8'))
card_name    = d['CardName']
card_name_fs = d['CardNameFS']
card_dir     = d['CardDir']
out_path     = d['OutputPath']
panels       = d['Panels']
cw           = d['CardWidth']
ch           = d['CardHeight']
th           = d['TitleHeight']
bw           = d['BodyWidth']
ph           = d['PanelHeight']
iw           = d['ImageWidth']
tw_area      = d['TextWidth']
title_ff     = d['TitleFont']
body_ff      = d['BodyFont']

BG    = (244, 237, 211)
TBG   = ( 44,  24,  16)
TFG   = (244, 237, 211)
PA    = (237, 229, 200)
PB    = (244, 237, 211)
TC    = ( 30,  18,   8)
LC    = (139, 105,  20)
AC    = ( 60,  36,  16)
DC    = (139, 105,  20)
PH_BG = (210, 190, 150)

bfs = 13
lfs = 12
lh  = 18
pad = 8
sm  = (cw - bw) // 2
gap_img = bw - tw_area - iw
ix      = sm + tw_area + gap_img
tw      = tw_area - 2 * pad

tf = resolve_font(title_ff, th - 2)
lf = resolve_font(title_ff, lfs)
bf = resolve_font(body_ff,  bfs)

total_body = ch - 2 * th
gap_panel  = (total_body - 3 * ph) // 4
pys = [th + gap_panel + i * (ph + gap_panel) for i in range(3)]

img  = Image.new('RGB', (cw, ch), BG)
draw = ImageDraw.Draw(img)

draw.rectangle([0, 0, cw, th], fill=TBG)
bb = draw.textbbox((0, 0), card_name, font=tf)
draw.text(((cw - bb[2] + bb[0]) // 2, (th - bb[3] + bb[1]) // 2), card_name, font=tf, fill=TFG)

orientations = ['upright', 'between', 'reversed']
for i, (p, py) in enumerate(zip(panels, pys)):
    pbg = PA if i % 2 == 0 else PB
    draw.rectangle([sm, py, sm + bw, py + ph], fill=pbg)
    draw.line([sm, py,          sm + bw, py],          fill=DC, width=1)
    draw.line([sm, py + ph - 1, sm + bw, py + ph - 1], fill=DC, width=1)

    # Text area (left side)
    tx  = sm + pad
    ty  = py + pad
    bot = py + ph - pad
    draw.text((tx, ty), p['label'], font=lf, fill=LC)
    ty += lfs + 4
    ty = draw_block(draw, p['description'], bf, tx, ty, tw, bot, TC, lh)
    ty += 4
    if p['advice'] and ty + lh <= bot:
        draw_block(draw, 'Advice: ' + p['advice'], bf, tx, ty, tw, bot, AC, lh)

    # Image area (right side)
    ori_lower = orientations[i]
    art_path  = card_dir + '/CARDIMG_' + card_name_fs + '_' + ori_lower + '.png'
    if os.path.exists(art_path):
        art = Image.open(art_path).convert('RGB')
        art = art.resize((iw, ph), Image.LANCZOS)
        img.paste(art, (ix, py))
    else:
        draw.rectangle([ix, py, ix + iw, py + ph], fill=PH_BG)
        lb  = draw.textbbox((0, 0), p['label'], font=lf)
        lx  = ix + (iw - (lb[2] - lb[0])) // 2
        ly  = py + (ph - (lb[3] - lb[1])) // 2
        draw.text((lx, ly), p['label'], font=lf, fill=LC)

    # Vertical divider between text and image columns
    div_x = sm + tw_area + gap_img // 2
    draw.line([div_x, py + 4, div_x, py + ph - 4], fill=DC, width=1)

bt  = Image.new('RGB', (cw, th), TBG)
bd  = ImageDraw.Draw(bt)
bb2 = bd.textbbox((0, 0), card_name, font=tf)
bd.text(((cw - bb2[2] + bb2[0]) // 2, (th - bb2[3] + bb2[1]) // 2), card_name, font=tf, fill=TFG)
img.paste(bt.rotate(180), (0, ch - th))

os.makedirs(os.path.dirname(out_path), exist_ok=True)
img.save(out_path)
print('OK ' + os.path.basename(out_path))
`;

const scriptPath = path.join(tempDir, 'render_card_face.py').replace(/\\/g, '/');
fs.writeFileSync(scriptPath, pyScript, 'utf8');

for (const job of allJobs) {
  const dataPath = path.join(tempDir, 'cf_' + job.CardName.replace(/[^a-zA-Z0-9]/g, '_') + '.json').replace(/\\/g, '/');
  fs.writeFileSync(dataPath, JSON.stringify(job), 'utf8');

  try {
    const out = execFileSync(
      job.PythonExe,
      [scriptPath, dataPath],
      { encoding: 'utf8', timeout: 30000 }
    );
    console.log('[Card Faces] ' + out.trim());
    results.push({ CardName: job.CardName, OutputPath: job.OutputPath, Status: 'OK' });
  } catch (e) {
    const errMsg = ((e.stderr || '') + (e.message || '')).slice(0, 400);
    console.warn('[Card Faces] Error for ' + job.CardName + ': ' + errMsg);
    errors.push({ CardName: job.CardName, OutputPath: job.OutputPath, Status: 'Error', error: errMsg });
  }

  try { fs.unlinkSync(dataPath); } catch (_) {}
}

try { fs.unlinkSync(scriptPath); } catch (_) {}
try { fs.rmdirSync(tempDir);     } catch (_) {}

if (results.length === 0) {
  throw new Error(
    '[Generate Card Faces] All ' + errors.length + ' jobs failed. First error: ' +
    (errors[0] && errors[0].error)
  );
}

if (errors.length > 0) {
  console.warn('[Generate Card Faces] Completed with ' + errors.length + ' errors (' + results.length + ' succeeded).');
}

return [...results, ...errors].map(function(r) { return { json: r }; });

const all    = $input.all().map(function(i) { return i.json; });
const ok     = all.filter(function(j) { return j.Status === 'OK'; });
const failed = all.filter(function(j) { return j.Status === 'Error'; });

console.log('[Report] Card faces: ' + ok.length + ' succeeded, ' + failed.length + ' failed of ' + all.length + ' total.');

if (failed.length > 0) {
  console.warn('[Report] Failed cards:');
  failed.forEach(function(f) {
    console.warn('  ' + f.CardName + ': ' + f.error);
  });
}

return [{
  json: {
    succeeded:   ok.length,
    failed:      failed.length,
    total:       all.length,
    failedCards: failed.map(function(f) { return { card: f.CardName, error: f.error }; })
  }
}];
